import{_ as a,o as e,c as s,ae as i}from"./chunks/framework.B6gjLfeO.js";const k=JSON.parse('{"title":"Filter Ad Network Data","description":"","frontmatter":{"title":"Filter Ad Network Data","slug":"filtering-ad-network-data"},"headers":[],"relativePath":"developer-hub/filtering-ad-network-data.md","filePath":"developer-hub/filtering-ad-network-data.md"}'),n={name:"developer-hub/filtering-ad-network-data.md"};function r(o,t,l,h,d,p){return e(),s("div",null,[...t[0]||(t[0]=[i(`<h2 id="what" tabindex="-1">What? <a class="header-anchor" href="#what" aria-label="Permalink to &quot;What?&quot;">​</a></h2><p>We take our customers’ privacy very seriously. To enable our customers to customize their event data flows to Branch’s different ad partners, we provide the Ad Network Data Filtering feature that allows you to limit the scope of event data exported to Branch’s ad partners. This way, if you want to filter out a subset of event data so that it is not exported to a particular ad network, or if you otherwise determine that a particular end user subset of event data should not be processed by a particular ad partner, you can continue to make use of Branch’s integration with that ad partner for other event data sets.</p><h2 id="why" tabindex="-1">Why? <a class="header-anchor" href="#why" aria-label="Permalink to &quot;Why?&quot;">​</a></h2><p>Branch has a broad set of integrated partners that help our links work seamlessly across channels and platforms. Our strong partner relationships make deployment and speed-to-market easy to achieve. Use our network of partners to harness the power of Branch in the way that best fits your business objectives. You can learn more about the types of ad partnerships Branch has integrations with here: <a href="https://branch.io/partners/" target="_blank" rel="noreferrer">https://branch.io/partners/</a>. We understand that some customers would like to filter the scope of end user event data sent to ad partners to ensure that events for certain end users are not exported. For this reason, we make available to our customers the Ad Network Data Filtering feature.</p><h2 id="set-event-flag" tabindex="-1">Set Event Flag <a class="header-anchor" href="#set-event-flag" aria-label="Permalink to &quot;Set Event Flag&quot;">​</a></h2><p>Before you can apply the data filter to your ad network via the Branch Dashboard, you must set an event flag per user.</p><p>Once this is set to <code>true</code> for a user, Branch will set a flag on every event for that user for it to be potentially filtered.</p><p>By default, Branch sets this flag to <code>false</code>.</p><div class="vp-code-group vp-adaptive-theme"><div class="tabs"><input type="radio" name="group-1CkTx" id="tab-TJw0ESq" checked><label data-title="Android - Java" for="tab-TJw0ESq">Android - Java</label><input type="radio" name="group-1CkTx" id="tab-hhtQzv3"><label data-title="Android - Kotlin" for="tab-hhtQzv3">Android - Kotlin</label><input type="radio" name="group-1CkTx" id="tab-dNvNLoY"><label data-title="iOS - Swift" for="tab-dNvNLoY">iOS - Swift</label><input type="radio" name="group-1CkTx" id="tab-hQe9rqS"><label data-title="iOS - Objective-C" for="tab-hQe9rqS">iOS - Objective-C</label></div><div class="blocks"><div class="language-java vp-adaptive-theme active"><button title="Copy Code" class="copy"></button><span class="lang">java</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Branch.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">getInstance</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">().</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">disableAdNetworkCallouts</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span></code></pre></div><div class="language-kotlin vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">kotlin</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Branch.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">getInstance</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">().</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">disableAdNetworkCallouts</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><div class="language-swift vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">swift</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">let</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> branch </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Branch.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">getInstance</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">()</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">branch.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">disableAdNetworkCallouts</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><div class="language-objectivec vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">objectivec</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Branch *branch = [Branch getInstance];</span></span>
<span class="line"><span>[branch disableAdNetworkCallouts:YES];</span></span></code></pre></div></div></div><h2 id="select-ad-network-to-filter" tabindex="-1">Select Ad Network to Filter <a class="header-anchor" href="#select-ad-network-to-filter" aria-label="Permalink to &quot;Select Ad Network to Filter&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Self Attributing Networks (SANs) Only</p><p>At this time, only data filtering can only be applied to Self Attributing Networks.</p><p>You can view a list of these partners <a href="./self-attributing-networks-sans.html">here</a>.</p></div><p>To filter the data that is sent to a SAN:</p><ol><li>In the left-hand navigation, under <strong>Channels &amp; Links</strong>, click <strong>Ads</strong> and then <strong>Partner Management</strong>.</li><li>Search for and select the SAN that you want to filter the data Branch sends.</li><li>Click on the <strong>Events Config</strong> tab and scroll down to the <strong>Restrict ad network data sharing</strong> toggle.</li><li>Click the toggle to turn it on and click <strong>Save</strong>.</li></ol><p><em>[Image: 1794]</em></p>`,14)])])}const u=a(n,[["render",r]]);export{k as __pageData,u as default};
